/* ── Core i18n engine ── */
function detectBrowserLang() {
    const nav = navigator.language || navigator.userLanguage || 'en';
    const langCode = nav.toLowerCase().split('-')[0];
    
    // Check for traditional chinese
    if (langCode === 'zh') {
        const full = nav.toLowerCase();
        if (full.includes('tw') || full.includes('hk') || full.includes('hant')) return 'zt';
        return 'zh';
    }
    
    // Check if we support this exact lang code
    if (window.PDFStar_LANGS[langCode]) {
        return langCode;
    }
    
    // Fallback to English
    return 'en';
}

// User preference or auto-detect browser language
let _currentLang = localStorage.getItem('PDFStar-lang') || detectBrowserLang();

function t(key) {
    const entry = window.T[key];
    if (!entry) return key;
    return entry[_currentLang] || entry['en'] || key;
}

function applyLang(lang) {
    _currentLang = lang;
    localStorage.setItem('PDFStar-lang', lang);
    const cfg = window.PDFStar_LANGS[lang];
    document.documentElement.lang = lang;
    document.documentElement.dir = cfg?.dir || 'ltr';

    // Update all data-i18n elements
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.dataset.i18n;
        const text = t(key);
        if (el.tagName === 'INPUT') el.placeholder = text;
        else el.innerHTML = text; // allow <br> to render in text
    });

    // Update lang dropdown label
    const btn = document.getElementById('langToggle');
    if (btn) btn.innerHTML = `${cfg?.flag || ''} ${cfg?.name || lang}`;

    // Update search placeholder specifically
    const sp = document.getElementById('toolSearch');
    if (sp) sp.placeholder = t('search-placeholder');
}

function toggleLang() {
    // Show/hide dropdown
    let dd = document.getElementById('langDropdown');
    if (!dd) {
        dd = document.createElement('div');
        dd.id = 'langDropdown';
        dd.className = 'lang-dropdown';
        dd.innerHTML = Object.entries(window.PDFStar_LANGS).map(([code, cfg]) =>
            `<button class="lang-item${code === _currentLang ? ' active' : ''}" onclick="selectLang('${code}')">${cfg.flag} ${cfg.name}</button>`
        ).join('');
        document.getElementById('langToggle').after(dd);
        setTimeout(() => document.addEventListener('click', closeLangDropdown, { once: true }), 100);
    } else {
        dd.remove();
    }
}

function selectLang(code) {
    applyLang(code);
    const dd = document.getElementById('langDropdown');
    if (dd) dd.remove();
}

function closeLangDropdown(e) {
    const dd = document.getElementById('langDropdown');
    if (dd && !dd.contains(e.target)) dd.remove();
}

// Init on load
document.addEventListener('DOMContentLoaded', () => applyLang(_currentLang));
